这个函数的功能是什么？
function NormaltoWCODE() {
    if (nowmode == "normal") {
        $("#infobox_normal").hide();
        nowmode = "normal";
        info = new Array();
        ids = new Object();
        props = new Object();
        input_num = $("#infobox_normal input.id").length;
        ids = $("#infobox_normal input.id");
        props = $("#infobox_normal input.prop");
        for (i = 0; i < input_num; i++) {
            id = $(ids).get(i);
            prop = $(props).get(i);
            if ($(id).hasClass('multiKey')) {
                multiKey = $(id).val();
                info[multiKey] = new Object();
                var subKey = 0;
                i++;
                id = $(ids).get(i);
                prop = $(props).get(i);
                while (($(id).hasClass('multiSubKey') || $(prop).hasClass('multiSubVal')) && i < input_num) {
                    if (isNaN($(id).val())) {
                        info[multiKey][subKey] = {
                            key: $(id).val(),
                            value: $(prop).val()
                        };
                    } else {
                        info[multiKey][subKey] = $(prop).val();
                    }
                    subKey++;
                    i++;
                    id = $(ids).get(i);
                    prop = $(props).get(i);
                }
                i--;
            } else if ($.trim($(id).val()) != "") {
                info[$(id).val()] = $(prop).val();
            }
        }
        wcode = WCODEDump(info);
        $(infoboxid).val(wcode);
        nowmode = "wcode";
        $(infoboxid).show();
    }
}
